const SYSCOM_CLIENT_ID     = 'zq2u2Zr1VFGam5IzAg5UolwmeSnsChP7';
const SYSCOM_CLIENT_SECRET = 'thdUXtjZunSRT4IB1ascUHIZlWsA5PhtIL9mBWVz';
const CATS = [
  {id:22, nombre:'Videovigilancia'},
  {id:37, nombre:'Control de Acceso'},
  {id:32, nombre:'Automatización'},
  {id:38, nombre:'Detección de Incendios'},
  {id:26, nombre:'Redes e IT'},
  {id:30, nombre:'Energía'},
  {id:25, nombre:'Radiocomunicación'},
  {id:27, nombre:'IoT/GPS'},
];
const MIN_DESCUENTO = 15;
const PAGES_PER_CAT = 4;
const TOP_GLOBAL    = 12;  // 10-15 productos
const MARGEN        = 0.20; // 20% margen utilidad sobre precio venta

let token;
try {
  const tokenResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://developers.syscom.mx/oauth/token',
    headers: {'Content-Type': 'application/x-www-form-urlencoded'},
    body: `client_id=${SYSCOM_CLIENT_ID}&client_secret=${SYSCOM_CLIENT_SECRET}&grant_type=client_credentials`
  });
  token = tokenResp.access_token;
} catch(e) {
  throw new Error('Error auth Syscom: ' + e.message);
}

let allPromos = [];
const seen = new Set();

for (const cat of CATS) {
  for (let p = 1; p <= PAGES_PER_CAT; p++) {
    let resp;
    try {
      resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://developers.syscom.mx/api/v1/productos?categoria=${cat.id}&pagina=${p}&moneda=MXN`,
        headers: {Authorization: `Bearer ${token}`}
      });
    } catch(e) { break; }
    const prods = resp.productos || [];
    if (!prods.length) break;
    for (const pr of prods) {
      const precios = pr.precios || {};
      const lista   = parseFloat(precios.precio_lista) || 0;
      const costo   = parseFloat(precios.precio_descuento) || lista;
      if (!lista || costo >= lista) continue;
      const pct = Math.round((1 - costo/lista)*100);
      if (pct < MIN_DESCUENTO) continue;

      // Deduplicar por título similar
      const key = (pr.titulo || pr.modelo || '').substring(0,40);
      if (seen.has(key)) continue;
      seen.add(key);

      // Precio Ocean Tech con margen 20% sobre precio venta
      const precioOcean = Math.ceil(costo / (1 - MARGEN));

      allPromos.push({
        titulo:       (pr.titulo || pr.modelo || '').substring(0,80),
        modelo:       pr.modelo || '',
        categoria:    cat.nombre,
        precioSyscom: costo,        // costo que paga Ocean Tech
        precioLista:  lista,        // precio lista Syscom (referencia)
        precioOcean:  precioOcean,  // precio venta Ocean Tech (+20% margen)
        descuentoPct: pct,          // % descuento vs lista Syscom
        ahorro:       lista - costo,
        imagen:       pr.img_portada || '',
        url:          `https://www.syscom.mx/producto/${pr.modelo}`,
      });
    }
  }
}

allPromos.sort((a,b) => b.descuentoPct - a.descuentoPct || b.ahorro - a.ahorro);
const top = allPromos.slice(0, TOP_GLOBAL);
const mejorDescuento = top.length ? top[0].descuentoPct : 0;
const mayorAhorro    = top.length ? Math.max(...top.map(p=>p.ahorro)).toFixed(0) : 0;

return [{json:{promos:top, mejorDescuento, mayorAhorro, totalPromos:top.length}}];

const {subject, html} = $input.first().json;
const ODOO_URL  = 'https://ocean-tech.odoo.com/jsonrpc';
const ODOO_DB   = 'ocean-tech';
const ODOO_UID  = 2;
const ODOO_PWD  = 'M1ercole$';
const LIST_ID   = 2;
const MODEL_ID  = 2462;

const sleep = ms => new Promise(r => setTimeout(r, ms));

const rpc = async (method, model, args, kwargs={}) => {
  // Reintentar hasta 3 veces si hay rate limit
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const r = await this.helpers.httpRequest({
        method: 'POST',
        url: ODOO_URL,
        body: JSON.stringify({
          jsonrpc:'2.0', method:'call', id:1,
          params:{service:'object', method:'execute_kw',
            args:[ODOO_DB, ODOO_UID, ODOO_PWD, model, method, args, kwargs]}
        }),
        headers: {'Content-Type':'application/json'}
      });
      if (r.error) throw new Error(JSON.stringify(r.error));
      return r.result;
    } catch(e) {
      if (attempt < 3 && (e.message.includes('429') || e.message.includes('503'))) {
        await sleep(attempt * 8000);
        continue;
      }
      throw e;
    }
  }
};

// Pequeña pausa inicial para evitar rate limit
await sleep(3000);

const mailingId = await rpc('create', 'mailing.mailing', [{
  subject:           subject,
  body_html:         html,
  mailing_model_id:  MODEL_ID,
  contact_list_ids:  [[4, LIST_ID]],
  reply_to:          'comercial@oceantech.com.mx',
  email_from:        'Ocean Tech <comercial@oceantech.com.mx>',
}]);

await rpc('action_send_mail', 'mailing.mailing', [[mailingId]]);

return [{json:{mailingId, subject, status:'sent'}}];

